from fastapi import APIRouter, Depends, HTTPExceptionfrom sqlalchemy.orm import Sessionfrom database import get_dbfrom models import Project, Item, Cellfrom pydantic import BaseModelfrom typing import Optionalimport uuidrouter = APIRouter()# --- Schemas ---class ProjectCreate(BaseModel):    name: str    template_id: Optional[str] = Noneclass ProjectUpdate(BaseModel):    name: Optional[str] = None    template_id: Optional[str] = None    status: Optional[str] = None    border_store_name: Optional[str] = None    border_date_range: Optional[str] = None    border_logo_url: Optional[str] = None    border_tagline: Optional[str] = None    border_notes: Optional[str] = None# --- Endpoints ---@router.get("/")def get_projects(db: Session = Depends(get_db)):    projects = db.query(Project).order_by(Project.updated_at.desc()).all()    return projects@router.post("/")def create_project(data: ProjectCreate, db: Session = Depends(get_db)):    project = Project(        id=str(uuid.uuid4()),        name=data.name,        template_id=data.template_id,    )    db.add(project)    db.commit()    db.refresh(project)    return project@router.get("/{project_id}")def get_project(project_id: str, db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    return project@router.patch("/{project_id}")def update_project(project_id: str, data: ProjectUpdate, db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    for field, value in data.model_dump(exclude_none=True).items():        setattr(project, field, value)    db.commit()    db.refresh(project)    return project@router.delete("/{project_id}")def delete_project(project_id: str, db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    db.delete(project)    db.commit()    return {"ok": True}@router.patch("/{project_id}/reorder")def reorder_items(project_id: str, positions: list[dict], db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    for entry in positions:        item = db.query(Item).filter(Item.id == entry["id"]).first()        if item and item.project_id == project_id:            item.position = entry["position"]    db.commit()    return {"ok": True}